    int k = 0, L = 0, R = 0, sum = 0;
    cin >> k >> L >> R;               // 读入 k 和区间 [L, R]
    for (int n = L; n <= R; n++)      // 逐个检查区间内的每个数
        if (n % 10 == k || n % k == 0)
            // n%10==k:个位是 k;n%k==0:是 k 的倍数。满足任一条件即"k 幸运数"
