#include<bits/stdc++.h>
using namespace std;
int main(){
    int h,m,s;
    cin>>h>>m>>s;                     // 读入开始时刻:时 h、分 m、秒 s
    int k;
    cin>>k;                           // 读入学习的总秒数 k
    int now=h*60*60+m*60+s;           // 第一步:把时刻统一换算成"总秒数"
    now+=k;                           // 第二步:加上学习时长
    int hh = now/3600;                // 第三步:拆回去 —— 总秒数 ÷ 3600 得小时
    now %= 3600;                      // 去掉整小时,剩下不足一小时的秒数
    int mm = now/60;                  // 剩余秒数 ÷ 60 得分钟
    now %= 60;                        // 再去掉整分钟,剩下的就是秒
    cout<<hh<<" "<<mm<<" "<<now<<"\n"; // 按 时 分 秒 输出(空格分隔)
    // "化总秒 → 加 → 拆回"三步,是所有时间进位题的通用模板
}

