    double V, G, M, N;                // 体积 V、重量 G、两档重量运费 M 和 N(都是小数)
    scanf("%lf%lf%lf%lf", &V, &G, &M, &N);
    double P_V = V / 2.0;             // 按体积计费:0.5 × V,即 V/2
    double P_G = (G < 300) ? M : N;   // 按重量计费:不到 300 克用第一档 M,否则第二档 N
                                      // (cond) ? A : B 是三目运算符:条件成立取 A,否则取 B
    double result = (P_V < P_G) ? P_V : P_G;  // 两种计费方式取更便宜的
    printf("%.1f\n", result);        // 保留一位小数输出
    return 0;
}

