            cout << "R\n";
        } else if (P <= 20) {         // 第二档:走到这里说明 P>10,再判 ≤20 → 显示 L
            cout << "L\n";           // else if 自带"前面都不满足",每档只需写上界
        } else {                      // 剩下的:电量正常,直接显示数字
            cout << P << '\n';
        }
    }
    return 0;
    // 易错:漏掉外层 while(T--) 只处理一组,是这类题最常见的零分原因
}

