#include <iostream>
using namespace std;
int main() {
    int H1, H2, H3, H4;
    cin >> H1 >> H2 >> H3 >> H4;      // H1 是 Alice 的身高,H2~H4 是其他三人

    int ans = H2;                     // 先让 2 号当"擂主"
    int d = H1 - H2;
    if (d < 0) d = -d;                // 手写绝对值:身高差取正
    int mnd = d;                      // mnd 记录当前最小身高差

    d = H1 - H3;                      // ---- 3 号上台打擂 ----
    if (d < 0) d = -d;
    if (d < mnd || (d == mnd && H3 < ans))
        // 两条换擂主的规则写在一个条件里:
        //   d < mnd          → 3 号离 Alice 更近,直接换
        //   d == mnd && 更矮  → 一样近时,矮的那个赢(题目的平手规则)
        ans = H3, mnd = d;            // 更新擂主和最小差

    d = H1 - H4;                      // ---- 4 号上台打擂,逻辑同上 ----
    if (d < 0) d = -d;
    if (d < mnd || (d == mnd && H4 < ans))
        ans = H4;

    cout << ans << endl;              // 最后站在台上的就是答案
    return 0;
}

