#include <iostream>
using namespace std;
int main() {
    int a, b = 0, t = 1;              // a:原数  b:新数(从 0 拼起)  t:数位权重(1,10,100…)
    cin >> a;
    while (a) {                       // 只要 a 还有数位就继续(a=0 时循环结束)
        if (a % 10 == 4)              // a%10 取出当前个位
            b += t * 8;               // 个位是 4 → 换成 8 拼进新数
        else
            b += t * (a % 10);        // 不是 4 → 原样拼进新数
        a /= 10;                      // 砍掉已处理的个位
        t *= 10;                      // 权重升一位(下次拼到十位、百位……)
    }
    cout << b;                        // 输出替换后的数
    // 特例:输入 0 时循环一次不进,b 保持初值 0,输出 0 恰好正确
    return 0;
}
